import type { Meta, StoryObj } from '@storybook/react-vite'
import {
  AtSign,
  CheckCheck,
  GitPullRequest,
  Heart,
  type LucideIcon,
  MessageSquare,
} from 'lucide-react'
import { useMemo, useState } from 'react'
import { expect, userEvent, within } from 'storybook/test'

import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import {
  Item,
  ItemActions,
  ItemContent,
  ItemDescription,
  ItemMedia,
  ItemTitle,
} from '@/components/ui/item'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'

/**
 * **Notifications** — a filterable activity feed. Shows `Tabs` as a filter,
 * `Item` as a rich row (icon, title, description and actions) and the use of an
 * "unread" dot + a count `Badge` that react to local state.
 */
const meta = {
  title: 'Examples/Notifications',
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        component:
          'A filterable activity feed: `Tabs` switch between all / unread / ' +
          'mentions, each row is an `Item` with media, content and actions, and an ' +
          'unread dot plus a count `Badge` track local state.',
      },
    },
  },
} satisfies Meta

export default meta

type Story = StoryObj<typeof meta>

type Kind = 'comment' | 'mention' | 'pr' | 'like'

type Note = {
  id: string
  kind: Kind
  title: string
  description: string
  when: string
  read: boolean
}

const ICONS: Record<Kind, LucideIcon> = {
  comment: MessageSquare,
  mention: AtSign,
  pr: GitPullRequest,
  like: Heart,
}

const initial: Note[] = [
  {
    id: '1',
    kind: 'mention',
    title: 'Bruno Lima mentioned you',
    description: '“@ana can you review the contrast tokens?” in #design-system',
    when: '5 min ago',
    read: false,
  },
  {
    id: '2',
    kind: 'pr',
    title: 'PR #128 awaiting review',
    description: 'feat(table): row grouping with sticky header',
    when: '1 hour ago',
    read: false,
  },
  {
    id: '3',
    kind: 'comment',
    title: 'Carla Dias commented',
    description: 'I love the new Donut chart on the dashboard!',
    when: '3 hours ago',
    read: false,
  },
  {
    id: '4',
    kind: 'like',
    title: 'Diego Reis liked your update',
    description: 'Release v0.4 — new accessible text tokens',
    when: 'yesterday',
    read: true,
  },
  {
    id: '5',
    kind: 'mention',
    title: 'Elena Prado mentioned you',
    description: '“@ana we close the sprint tomorrow” in #product',
    when: 'yesterday',
    read: true,
  },
]

function NotificationsFeed() {
  const [notes, setNotes] = useState(initial)
  const [tab, setTab] = useState<'all' | 'unread' | 'mentions'>('all')

  const unreadCount = notes.filter((n) => !n.read).length

  const visible = useMemo(() => {
    if (tab === 'unread') return notes.filter((n) => !n.read)
    if (tab === 'mentions') return notes.filter((n) => n.kind === 'mention')
    return notes
  }, [notes, tab])

  function markRead(id: string) {
    setNotes((prev) => prev.map((n) => (n.id === id ? { ...n, read: true } : n)))
  }

  function markAll() {
    setNotes((prev) => prev.map((n) => ({ ...n, read: true })))
  }

  return (
    <div className="mx-auto max-w-2xl py-2">
      <Card>
        <CardHeader className="flex flex-row items-center justify-between gap-2">
          <CardTitle className="flex items-center gap-2">
            Notifications
            {unreadCount > 0 ? <Badge>{unreadCount}</Badge> : null}
          </CardTitle>
          <Button
            variant="ghost"
            size="sm"
            onClick={markAll}
            disabled={unreadCount === 0}
          >
            <CheckCheck className="size-4" aria-hidden="true" /> Mark all
          </Button>
        </CardHeader>

        <CardContent>
          <Tabs value={tab} onValueChange={(v) => setTab(v as typeof tab)}>
            <TabsList className="w-full">
              <TabsTrigger value="all" className="flex-1">
                All
              </TabsTrigger>
              <TabsTrigger value="unread" className="flex-1">
                Unread
              </TabsTrigger>
              <TabsTrigger value="mentions" className="flex-1">
                Mentions
              </TabsTrigger>
            </TabsList>

            <TabsContent value={tab} className="pt-3">
              <div className="flex flex-col gap-1">
                {visible.map((note) => {
                  const Icon = ICONS[note.kind]
                  return (
                    <Item key={note.id} variant={note.read ? 'default' : 'muted'}>
                      <ItemMedia variant="icon">
                        <Icon className="size-4" aria-hidden="true" />
                      </ItemMedia>
                      <ItemContent>
                        <ItemTitle className="flex items-center gap-2">
                          {note.title}
                          {!note.read ? (
                            <>
                              <span
                                className="size-2 rounded-full bg-primary"
                                aria-hidden="true"
                              />
                              <span className="sr-only">Unread</span>
                            </>
                          ) : null}
                        </ItemTitle>
                        <ItemDescription>{note.description}</ItemDescription>
                        <ItemDescription className="text-xs">{note.when}</ItemDescription>
                      </ItemContent>
                      <ItemActions>
                        {!note.read ? (
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => markRead(note.id)}
                          >
                            Mark read
                          </Button>
                        ) : null}
                      </ItemActions>
                    </Item>
                  )
                })}
                {visible.length === 0 ? (
                  <p className="py-10 text-center text-muted-foreground text-sm">
                    All caught up. No notifications here.
                  </p>
                ) : null}
              </div>
            </TabsContent>
          </Tabs>
        </CardContent>
      </Card>
    </div>
  )
}

export const Default: Story = {
  render: () => <NotificationsFeed />,
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement)
    // Starts with 3 unread; the "Unread" filter shows exactly those.
    await expect(canvas.getByText('3')).toBeInTheDocument()
    await userEvent.click(canvas.getByRole('tab', { name: 'Unread' }))
    const markButtons = canvas.getAllByRole('button', { name: 'Mark read' })
    await expect(markButtons).toHaveLength(3)
    // Marking all resets the counter and disables the button.
    await userEvent.click(canvas.getByRole('button', { name: /Mark all/ }))
    await expect(
      canvas.queryByRole('button', { name: 'Mark read' }),
    ).not.toBeInTheDocument()
  },
}

import type { Meta, StoryObj } from '@storybook/react-vite'
import { MoreHorizontal, Search, UserPlus } from 'lucide-react'
import { useMemo, useState } from 'react'
import { expect, userEvent, within } from 'storybook/test'

import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardHeader } from '@/components/ui/card'
import { Checkbox } from '@/components/ui/checkbox'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import { InputGroup, InputGroupAddon, InputGroupInput } from '@/components/ui/input-group'
import { PaginationShort } from '@/components/ui/pagination'
import { Select } from '@/components/ui/select'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'

/**
 * **Team** — a data-driven management screen. It brings together search (`InputGroup`),
 * filtering (`Select`), row selection (`Checkbox` + `data-state="selected"`),
 * status with `Badge`, per-row actions in `DropdownMenu` and `PaginationShort`,
 * all inside a `Card`.
 */
const meta = {
  title: 'Examples/Team',
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        component:
          'A data-management screen: a searchable, filterable, paginated `Table` ' +
          'with row selection, avatars, role and status `Badge`s and per-row ' +
          '`DropdownMenu` actions — wrapped in a `Card` toolbar.',
      },
    },
  },
} satisfies Meta

export default meta

type Story = StoryObj<typeof meta>

type Status = 'Active' | 'Invited' | 'Inactive'

type Member = {
  id: string
  name: string
  email: string
  role: string
  status: Status
  img: number
}

const members: Member[] = [
  {
    id: '1',
    name: 'Ana Souza',
    email: 'ana@timds.dev',
    role: 'Admin',
    status: 'Active',
    img: 47,
  },
  {
    id: '2',
    name: 'Bruno Lima',
    email: 'bruno@timds.dev',
    role: 'Dev',
    status: 'Active',
    img: 12,
  },
  {
    id: '3',
    name: 'Carla Dias',
    email: 'carla@timds.dev',
    role: 'Design',
    status: 'Invited',
    img: 5,
  },
  {
    id: '4',
    name: 'Diego Reis',
    email: 'diego@timds.dev',
    role: 'Dev',
    status: 'Active',
    img: 33,
  },
  {
    id: '5',
    name: 'Elena Prado',
    email: 'elena@timds.dev',
    role: 'Product',
    status: 'Inactive',
    img: 24,
  },
  {
    id: '6',
    name: 'Felipe Nunes',
    email: 'felipe@timds.dev',
    role: 'Dev',
    status: 'Active',
    img: 8,
  },
  {
    id: '7',
    name: 'Gabi Rocha',
    email: 'gabi@timds.dev',
    role: 'Design',
    status: 'Invited',
    img: 16,
  },
  {
    id: '8',
    name: 'Hugo Mello',
    email: 'hugo@timds.dev',
    role: 'Product',
    status: 'Active',
    img: 51,
  },
]

const statusVariant: Record<Status, 'success' | 'warning' | 'secondary'> = {
  Active: 'success',
  Invited: 'warning',
  Inactive: 'secondary',
}

const roleOptions = [
  { value: 'all', label: 'All roles' },
  { value: 'Admin', label: 'Admin' },
  { value: 'Dev', label: 'Dev' },
  { value: 'Design', label: 'Design' },
  { value: 'Product', label: 'Product' },
]

const PAGE_SIZE = 5

function TeamTable() {
  const [query, setQuery] = useState('')
  const [role, setRole] = useState('all')
  const [page, setPage] = useState(1)
  const [selected, setSelected] = useState<Set<string>>(new Set())

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase()
    return members.filter((m) => {
      const matchesQuery =
        !q || m.name.toLowerCase().includes(q) || m.email.toLowerCase().includes(q)
      const matchesRole = role === 'all' || m.role === role
      return matchesQuery && matchesRole
    })
  }, [query, role])

  const totalPages = Math.max(1, Math.ceil(filtered.length / PAGE_SIZE))
  const current = Math.min(page, totalPages)
  const pageRows = filtered.slice((current - 1) * PAGE_SIZE, current * PAGE_SIZE)

  const allOnPageSelected =
    pageRows.length > 0 && pageRows.every((m) => selected.has(m.id))

  function toggle(id: string) {
    setSelected((prev) => {
      const next = new Set(prev)
      if (next.has(id)) {
        next.delete(id)
      } else {
        next.add(id)
      }
      return next
    })
  }

  function toggleAllOnPage() {
    setSelected((prev) => {
      const next = new Set(prev)
      if (allOnPageSelected) {
        for (const m of pageRows) next.delete(m.id)
      } else {
        for (const m of pageRows) next.add(m.id)
      }
      return next
    })
  }

  return (
    <div className="mx-auto flex max-w-4xl flex-col gap-4 py-2">
      <div className="flex flex-wrap items-end justify-between gap-3">
        <div className="flex flex-col gap-1">
          <h1 className="font-bold text-2xl tracking-tight">Team</h1>
          <p className="text-muted-foreground">
            {filtered.length} {filtered.length === 1 ? 'member' : 'members'}
            {selected.size > 0 ? ` · ${selected.size} selected` : ''}
          </p>
        </div>
        <Button>
          <UserPlus className="size-4" aria-hidden="true" /> Invite
        </Button>
      </div>

      <Card className="overflow-hidden p-0">
        <CardHeader className="flex flex-col gap-3 border-b p-4 sm:flex-row sm:items-center sm:justify-between">
          <InputGroup className="sm:max-w-xs">
            <InputGroupAddon>
              <Search className="size-4" aria-hidden="true" />
            </InputGroupAddon>
            <InputGroupInput
              placeholder="Search by name or email..."
              aria-label="Search members"
              value={query}
              onChange={(e) => {
                setQuery(e.target.value)
                setPage(1)
              }}
            />
          </InputGroup>
          <Select
            options={roleOptions}
            defaultValue="all"
            aria-label="Filter by role"
            onValueChange={(v) => {
              setRole(v as string)
              setPage(1)
            }}
            triggerClassName="sm:w-48"
          />
        </CardHeader>

        <CardContent className="p-0">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="w-10">
                  <Checkbox
                    aria-label="Select all on this page"
                    checked={allOnPageSelected}
                    onCheckedChange={toggleAllOnPage}
                  />
                </TableHead>
                <TableHead>Member</TableHead>
                <TableHead>Role</TableHead>
                <TableHead>Status</TableHead>
                <TableHead className="w-10 text-right">
                  <span className="sr-only">Actions</span>
                </TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {pageRows.map((m) => (
                <TableRow
                  key={m.id}
                  data-state={selected.has(m.id) ? 'selected' : undefined}
                >
                  <TableCell>
                    <Checkbox
                      aria-label={`Select ${m.name}`}
                      checked={selected.has(m.id)}
                      onCheckedChange={() => toggle(m.id)}
                    />
                  </TableCell>
                  <TableCell>
                    <div className="flex items-center gap-3">
                      <Avatar className="size-8">
                        <AvatarImage
                          src={`https://i.pravatar.cc/80?img=${m.img}`}
                          alt={m.name}
                        />
                        <AvatarFallback>
                          {m.name
                            .split(' ')
                            .map((n) => n[0])
                            .join('')}
                        </AvatarFallback>
                      </Avatar>
                      <div className="flex flex-col">
                        <span className="font-medium">{m.name}</span>
                        <span className="text-muted-foreground text-xs">{m.email}</span>
                      </div>
                    </div>
                  </TableCell>
                  <TableCell>
                    <Badge variant="outline">{m.role}</Badge>
                  </TableCell>
                  <TableCell>
                    <Badge variant={statusVariant[m.status]}>{m.status}</Badge>
                  </TableCell>
                  <TableCell className="text-right">
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button
                          variant="ghost"
                          size="icon"
                          aria-label={`Actions for ${m.name}`}
                        >
                          <MoreHorizontal className="size-4" aria-hidden="true" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuLabel>Actions</DropdownMenuLabel>
                        <DropdownMenuItem>View profile</DropdownMenuItem>
                        <DropdownMenuItem>Edit role</DropdownMenuItem>
                        <DropdownMenuSeparator />
                        <DropdownMenuItem variant="destructive">
                          Remove from team
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </TableCell>
                </TableRow>
              ))}
              {pageRows.length === 0 ? (
                <TableRow>
                  <TableCell
                    colSpan={5}
                    className="h-24 text-center text-muted-foreground"
                  >
                    No members found.
                  </TableCell>
                </TableRow>
              ) : null}
            </TableBody>
          </Table>
        </CardContent>
      </Card>

      <div className="flex justify-end">
        <PaginationShort page={current} total={totalPages} onPageChange={setPage} />
      </div>
    </div>
  )
}

export const Default: Story = {
  render: () => <TeamTable />,
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement)
    // Searching narrows the list down to a single member.
    await userEvent.type(canvas.getByLabelText('Search members'), 'bruno')
    await expect(canvas.getByText('Bruno Lima')).toBeInTheDocument()
    await expect(canvas.queryByText('Ana Souza')).not.toBeInTheDocument()
    // Selecting the row marks the "selected" state.
    await userEvent.click(canvas.getByRole('checkbox', { name: 'Select Bruno Lima' }))
    await expect(canvas.getByText(/1 selected/)).toBeInTheDocument()
  },
}
